"use client"

import React, { useState } from 'react';
import styles from './drug.module.css';

// ⭐️ 백엔드 Entity/DTO와 이름을 맞춘 인터페이스
interface DrugItem {
    itemSeq: string;     // 품목코드 (고유 ID)
    itemName: string;    // 약 이름
    entpName: string;    // 제조사
    efficacy: string;    // 효능 (백엔드에서 변환됨)
    useMethod: string;   // 용법
    caution: string;     // 주의사항
    itemImage: string | null; // 이미지 (없을 수 있음)
}

export default function DrugSearchPage() {
    const [keyword, setKeyword] = useState('');
    const [results, setResults] = useState<DrugItem[]>([]);
    const [loading, setLoading] = useState(false);

    // 🧹 텍스트 정리 함수
    // [e약은요] 데이터는 가끔 <p> 태그나 줄바꿈 문자가 섞여 있어서 이걸 청소해줍니다.
    const cleanText = (text: string) => {
        if (!text) return "정보 없음";
        // 1. HTML 태그 제거 (<p>, <br> 등)
        let cleaned = text.replace(/<[^>]*>?/g, ' '); 
        // 2. 불필요한 공백 정리
        cleaned = cleaned.replace(/\s+/g, ' ').trim();
        return cleaned;
    };

    const handleSearch = async () => {
        if (!keyword) {
            alert("약 이름을 입력해주세요!");
            return;
        }

        setLoading(true);
        try {
            // 백엔드 호출 (DB 조회 -> 없으면 API 호출 -> 자동 저장 -> 반환)
            const res = await fetch(`http://localhost:8080/api/drug/search?keyword=${keyword}`);
            
            if (res.ok) {
                const data = await res.json();
                setResults(data); 
            } else {
                alert("검색에 실패했습니다.");
            }
        } catch (e) {
            console.error(e);
            alert("서버와 연결할 수 없습니다.");
        } finally {
            setLoading(false);
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') handleSearch();
    };

    return (
        <div className={styles.container}>
            <h2 className={styles.title}>💊 e약은요 검색 (스마트 DB)</h2>
            
            {/* 검색창 */}
            <div className={styles.searchBox}>
                <input 
                    type="text" 
                    placeholder="약 이름을 입력하세요 (예: 타이레놀, 베아제)" 
                    value={keyword}
                    onChange={(e) => setKeyword(e.target.value)}
                    onKeyDown={handleKeyDown}
                    className={styles.input}
                />
                <button onClick={handleSearch} className={styles.btn}>검색</button>
            </div>

            {/* 결과 목록 */}
            <div className={styles.resultArea}>
                {loading ? (
                    <p className={styles.message}>약을 찾고 있습니다... 🔍<br/>(없는 약은 식약처에서 가져옵니다)</p>
                ) : results.length > 0 ? (
                    <div className={styles.grid}>
                        {results.map((drug, index) => (
                            <div key={index} className={styles.card}>
                                <div className={styles.imgWrapper}>
                                    {/* 이미지가 없으면 기본 이미지(no_drug_img.png) 사용 */}
                                    <img 
                                        src={drug.itemImage || "/img/no_drug_img.png"} 
                                        alt={drug.itemName} 
                                        onError={(e) => e.currentTarget.src = "/img/no_drug_img.png"}
                                    />
                                </div>
                                <div className={styles.content}>
                                    <span className={styles.company}>{drug.entpName}</span>
                                    <h3 className={styles.drugName}>{drug.itemName}</h3>
                                    
                                    <div className={styles.info}>
                                        <strong>효능/효과:</strong> 
                                        {/* 내용이 너무 길면 80자로 자름 */}
                                        <p>{cleanText(drug.efficacy).substring(0, 80)}
                                           {drug.efficacy && drug.efficacy.length > 80 ? "..." : ""}
                                        </p>
                                    </div>
                                    <div className={styles.info}>
                                        <strong>용법/용량:</strong> 
                                        <p>{cleanText(drug.useMethod).substring(0, 50)}
                                           {drug.useMethod && drug.useMethod.length > 50 ? "..." : ""}
                                        </p>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p className={styles.message}>검색 결과가 없습니다.</p>
                )}
            </div>
        </div>
    );
}